from flask import Blueprint, request, send_file
from werkzeug.utils import secure_filename
import os

invoices_blueprint = Blueprint('invoices', __name__)

@invoices_blueprint.route('/api/invoices/<int:invoice_id>/download', methods=['GET'])
def download_invoice(invoice_id):
    # Assuming invoices are stored in a directory with the same name as the invoice ID
    invoice_dir = f'/path/to/invoices/{invoice_id}'
    
    # Check if the invoice exists and is accessible by the user
    if not os.path.exists(invoice_dir) or not os.access(invoice_dir, os.R_OK):
        return 'Invoice not found or inaccessible', 404
    
    # Generate a unique filename for the download
    filename = secure_filename(f'invoice_{invoice_id}.pdf')
    
    # Return the PDF file as a response with the correct headers
    return send_file(os.path.join(invoice_dir, filename), mimetype='application/pdf',
                     attachment_filename=filename, as_attachment=True)